import { getPreferenceValues } from "@raycast/api";
import { execSync } from "node:child_process";

export const MULLVAD_DEVICE_TAG = "tag:mullvad-exit-node";

export type Location = {
  Country: string;
  CountryCode: string;
  City: string;
  CityCode: string;
  Latitude: number;
  Longitude: number;
  Priority: number;
};

export interface Device {
  self: boolean;
  key: string;
  name: string;
  userid: string;
  loginName?: string;
  dns: string;
  ipv4: string;
  ipv6: string;
  os: string;
  online: boolean;
  lastseen: Date;
  exitnode: boolean;
  exitnodeoption: boolean;
  ssh?: boolean;
  tags?: string[];
  location?: Location;
}

export class InvalidPathError extends Error {}
export class NotRunningError extends Error {}
export class NotConnectedError extends Error {}
export class ENOBUFSError extends Error {}
export class MaxBufferNaNError extends Error {}

export type StatusDevice = {
  ID: string;
  PublicKey: string;
  HostName: string;
  DNSName: string;
  OS: string;
  UserID: number;
  TailscaleIPs: string[];
  AllowedIPs: string[];
  Addrs: string[] | null;
  CurAddr: string;
  Relay: string;
  PeerRelay: string;
  RxBytes: number;
  TxBytes: number;
  Created: string;
  LastWrite: string;
  LastSeen: string;
  LastHandshake: string;
  Online: boolean;
  ExitNode: boolean;
  ExitNodeOption: boolean;
  Active: boolean;
  PeerAPIURL: string[] | null;
  TaildropTarget: number;
  NoFileSharingReason: string;
  InNetworkMap: boolean;
  InMagicSock: boolean;
  InEngine: boolean;
  /** Only present when the key has expired. */
  Expired?: boolean;
  KeyExpiry?: string;
  /** Present when the device advertises Tailscale SSH (sshHostKeys in status --json). */
  sshHostKeys?: string[];
  Tags?: string[];
  /** Only present on Self. */
  Capabilities?: string[];
  /** Only present on Self. */
  CapMap?: Record<string, null | string[]>;
  Location?: Location;
};

/**
 * StatusResponse is a subset of the fields returned by `tailscale status --json`.
 */
export type StatusResponse = {
  Version: string;
  BackendState: string;
  HaveNodeKey: boolean;
  AuthURL: string;
  TailscaleIPs: string[];
  Self: StatusDevice;
  Health: string[];
  MagicDNSSuffix: string;
  CurrentTailnet: {
    Name: string;
    MagicDNSSuffix: string;
    MagicDNSEnabled: boolean;
  };
  CertDomains: string[] | null;
  Peer: Record<string, StatusDevice>;
  User: Record<
    string,
    {
      ID: number;
      DisplayName: string;
      LoginName: string;
      ProfilePicURL?: string;
    }
  >;
  ClientVersion: null | unknown;
};

/**
 * NetcheckResponse are the fields returned by `tailscale netcheck --format json`.
 * These are mentioned to not be stable and may change in the future. Doubtful, but possible.
 */
